import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileHandler {

    private static final String BASE_PATH = "C:/myapp/files/";

    public static void readFile(String fileName) {
        try {
            File file = new File(BASE_PATH + fileName);
            if (file.getCanonicalPath().startsWith(new File(BASE_PATH).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);
                // read file contents
                fis.close();
            } else {
                System.out.println("Access to file outside the allowed directory is not permitted.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "../importantfile.txt";
        readFile(userInput);
    }
}

